- [ ] **Step 1: Adicionar loader (server) que monta AberturaData a partir da abertura atual**

Adicionar em `actions.ts`:

```typescript
import { ABERTURA_TEXT_FIELDS as TEXT_FIELDS } from '@/types/abertura';

export async function loadAberturaAtual(): Promise<{ data: AberturaData; docs: Partial<Record<DocKey, string>>; aberturaId: string } | null> {
  const supabase = await createServerClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return null;
  const { data: prof } = await supabase.from('profiles').select('current_company').eq('user_id', user.id).maybeSingle();
  if (!prof?.current_company) return null;
  const { data: ab } = await supabase.from('abertura_empresas').select('*').eq('company_id', prof.current_company).maybeSingle();
  if (!ab) return null;
  const data: AberturaData = { ...EMPTY_ABERTURA };
  for (const k of TEXT_FIELDS) {
    if (k === 'empresa_cnaes_secundarios') (data as any)[k] = (ab as any)[k] ?? [];
    else if (k === 'sede_mesmo_que_titular') (data as any)[k] = !!(ab as any)[k];
    else (data as any)[k] = (ab as any)[k] ?? '';
  }
  const docs: Partial<Record<DocKey, string>> = {};
  for (const k of DOC_KEYS) if ((ab as any)[k]) docs[k] = (ab as any)[k];
  return { data, docs, aberturaId: (ab as any).id };
}
```

- [ ] **Step 2: Atualizar a página para suportar `?modo=alteracao`**

